#include <stdio.h>
#include <string.h>

char board[8][9] = {0}; 

int checkBoard() {
  int i;
  for(i = 0; i < 8; i++) {
    if(strcmp(board[i], "BWBWBWBW") != 0 && strcmp(board[i], "WBWBWBWB") != 0) 
      return 0; 
  } 
  return 1; 
}

int main() {
  int i, j;
  char row[20]; 
  for(i = 0; i < 8; i++) {
    scanf("%s\n", row); 
    for(j = 0; j < 8; j++) 
      board[i][j] = row[j];   
  }

  if(checkBoard())
    printf("YES");
  else 
    printf("NO");  

  return 0; 
}

